+    fn delete_zone_removes_key_zone_bindings() {
+        let mut engine = ZoneSegmentationEngine::new();
+        engine
+            .register_zone(make_zone("staging", 70, 3, IsolationLevel::Permissive))
+            .unwrap();
+        engine.bind_key_to_zone("key-1", "staging");
